export interface AnimaEmotionPayload {
  readonly name: string
  readonly intensity: number
}

findings.suggestion:
Define a literal union type for valid Anima emotion names and constrain intensity:

export type AnimaEmotionName = 'happy' | 'sad' | 'angry' | 'think' | 'surprised' | 'awkward' | 'question' | 'curious' | 'neutral'

export interface AnimaEmotionPayload {
  readonly name: AnimaEmotionName
  readonly intensity: number  // semantically [0, 1], enforce at construction if needed
}

